simpleExample.code:
CREATE TABLE customers (
  id BIGINT PRIMARY KEY AUTO_INCREMENT,
  email VARCHAR(255) NOT NULL UNIQUE
);

-- One-to-Many: customers -> orders (FK on the 'many' side)
CREATE TABLE orders (
  id BIGINT PRIMARY KEY AUTO_INCREMENT,
  customer_id BIGINT NOT NULL,
  FOREIGN KEY (customer_id) REFERENCES customers(id)
);

-- One-to-One: orders -> shipping_addresses (UNIQUE FK)
CREATE TABLE shipping_addresses (
  id BIGINT PRIMARY KEY AUTO_INCREMENT,
  order_id BIGINT NOT NULL UNIQUE,
  city VARCHAR(100) NOT NULL,
  FOREIGN KEY (order_id) REFERENCES orders(id)
);

CREATE TABLE products (
  id BIGINT PRIMARY KEY AUTO_INCREMENT,
  name VARCHAR(200) NOT NULL,
  price DECIMAL(10,2) NOT NULL
);

-- Junction table: resolves orders <-> products (N:N)
CREATE TABLE order_items (
  id BIGINT PRIMARY KEY AUTO_INCREMENT,
  order_id BIGINT NOT NULL,
  product_id BIGINT NOT NULL,
  quantity INT NOT NULL DEFAULT 1,
  unit_price DECIMAL(10,2) NOT NULL,
  FOREIGN KEY (order_id) REFERENCES orders(id) ON DELETE CASCADE,
  FOREIGN KEY (product_id) REFERENCES products(id) ON DELETE RESTRICT,
  UNIQUE (order_id, product_id)
);

// HikariCP configuration tuned after diagnosing the timeouts
HikariConfig config = new HikariConfig();
config.setMaximumPoolSize(20);
config.setMinimumIdle(20);
config.setConnectionTimeout(5000);
config.setIdleTimeout(600000);
config.setMaxLifetime(1800000);
config.setLeakDetectionThreshold(2000);

// The leaking code path found via leak-detection logs
public Order findOrder(long orderId) throws SQLException {
    Connection conn = dataSource.getConnection();
    PreparedStatement stmt = conn.prepareStatement(
        "SELECT * FROM orders WHERE id = ?");
    stmt.setLong(1, orderId);
    ResultSet rs = stmt.executeQuery();
    if (!rs.next()) {
        throw new OrderNotFoundException(orderId); // conn.close() never runs
    }
    Order order = mapOrder(rs);
    conn.close();
    return order;
}

-- Composite index, leftmost column matches the most common filter
CREATE INDEX idx_orders_customer_status ON orders(customer_id, status);

-- Widened into a covering index: adds created_at (for the ORDER BY)
-- and total_amount (a selected column), so the engine never touches the table
CREATE INDEX idx_orders_covering
  ON orders(customer_id, status, created_at, total_amount);

