START TRANSACTION;

UPDATE accounts SET balance = balance - 500 WHERE id = 1;
UPDATE accounts SET balance = balance + 500 WHERE id = 2;

COMMIT;

-- Variant with a savepoint: a multi-step order flow where a
-- discount step might legitimately fail without aborting everything
START TRANSACTION;
UPDATE customers SET loyalty_points = loyalty_points - 200 WHERE id = 501;
SAVEPOINT before_discount;
UPDATE orders SET discount_applied = true, total = total - 50
WHERE id = 9001 AND total >= 50;
-- discount ineligible (0 rows affected) -> undo just that step:
ROLLBACK TO SAVEPOINT before_discount;
INSERT INTO orders (id, customer_id, total, discount_applied)
VALUES (9001, 501, 500, false);
COMMIT;

-- Transaction A
START TRANSACTION ISOLATION LEVEL READ_COMMITTED;
SELECT balance FROM accounts WHERE id = 1;
-- ... Transaction B commits a change to accounts.id = 1 here ...
SELECT balance FROM accounts WHERE id = 1;
COMMIT;

architectureFlow.mermaid:
graph TD
    A["Transaction requests access to a row"] --> B{"What kind of access?"}
    B -- "Read" --> C{"Row has an exclusive lock held?"}
    C -- "No" --> D["Acquire shared lock - proceed to read"]
    C -- "Yes" --> E["Wait for exclusive lock to release"]
    B -- "Write" --> F{"Row has any lock held by another transaction?"}
    F -- "No" --> G["Acquire exclusive lock - proceed to write"]
    F -- "Yes" --> H["Wait for existing lock to release"]
    H --> I{"Waiting forms a cycle - deadlock?"}
    I -- "Yes" --> J["Database aborts one transaction as the victim"]
    I -- "No" --> G

